WITH m AS (
  SELECT ST_GeomFromEWKT((SELECT omrade_ewkt FROM (SELECT ST_AsEWKT(omrade) AS omrade_ewkt FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Kristiansand%') AS k LIMIT 1)) AS geom
), s AS (
  SELECT id, ST_AsEWKT(omrade) AS omrade_ewkt
  FROM stormflohavniva_bd7c84ed67254396b81e18b48ee0f525.stormflo200ar_klimaarna
  WHERE ST_Intersects(omrade, (SELECT geom FROM m))
)
SELECT id, omrade_ewkt
FROM s;

